20	using Microsoft.Extensions.Logging;
21	
22	using Quartz.Diagnostics;
23	
24	namespace Quartz.Listener;
25	
26	/// <summary>
27	/// Keeps a collection of mappings of which Job to trigger after the completion
28	/// of a given job.  If this listener is notified of a job completing that has a
29	/// mapping, then it will then attempt to trigger the follow-up job.  This
30	/// achieves "job chaining", or a "poor man's workflow".
31	///</summary>
32	/// <remarks>
33	/// <para>
34	/// Generally an instance of this listener would be registered as a global
35	/// job listener, rather than being registered directly to a given job.
36	/// </para>
37	/// <para>
38	/// If for some reason there is a failure creating the trigger for the
39	/// follow-up job (which would generally only be caused by a rare serious
40	/// failure in the system, or the non-existence of the follow-up job), an error
41	/// message is logged, but no other action is taken. If you need more rigorous
42	/// handling of the error, consider scheduling the triggering of the flow-up
43	/// job within your job itself.
44	/// </para>
45	///</remarks>
46	/// <author>James House</author>
47	/// <author>Marko Lahma (.NET)</author>
48	public sealed class JobChainingJobListener : JobListenerSupport
49	{
50	    private readonly Dictionary<JobKey, JobKey> chainLinks;
51	    private readonly ILogger<JobChainingJobListener> logger;
52	
53	    /// <summary>
54	    /// Construct an instance with the given name.
55	    /// </summary>
56	    /// <param name="name">The name of this instance.</param>
57	    public JobChainingJobListener(string name)
58	    {
59	        if (name is null)
60	        {
61	            Throw.ArgumentException("Listener name cannot be null!");
62	        }
63	        Name = name;
64	        chainLinks = new Dictionary<JobKey, JobKey>();
65	        logger = LogProvider.CreateLogger<JobChainingJobListener>();
66	    }
67	
68	    public override string Name { get; }
69	
70	    /// <summary>
71	    /// Add a chain mapping - when the Job identified by the first key completes
72	    /// the job identified by the second key will be triggered.
73	    /// </summary>
74	    /// <param name="firstJob">a JobKey with the name and group of the first job</param>
75	    /// <param name="secondJob">a JobKey with the name and group of the follow-up job</param>
76	    public void AddJobChainLink(JobKey firstJob, JobKey secondJob)
77	    {
78	        if (firstJob is null || secondJob is null)
79	        {
80	            Throw.ArgumentException("Key cannot be null!");
81	        }
82	        if (firstJob.Name is null || secondJob.Name is null)
83	        {
84	            Throw.ArgumentException("Key cannot have a null name!");
85	        }
86	
87	        chainLinks.Add(firstJob, secondJob);
88	    }
89	
90	    public override async ValueTask JobWasExecuted(IJobExecutionContext context,
91	        JobExecutionException? jobException,
92	        CancellationToken cancellationToken = default)
93	    {
94	        chainLinks.TryGetValue(context.JobDetail.Key, out var sj);
95	
96	        if (sj is null)
97	        {
98	            return;
99	        }
100	
101	        logger.LogInformation("Job '{JobKey}' will now chain to Job '{Job}'", context.JobDetail.Key, sj);
102	
103	        try
104	        {
105	            await context.Scheduler.TriggerJob(sj, cancellationToken).ConfigureAwait(false);
106	        }
107	        catch (SchedulerException se)
108	        {
109	            logger.LogError(se, "Error encountered during chaining to Job '{Job}'", sj);
110	        }
111	    }
112	}

