22	using System.Collections.Concurrent;
23	using System.Globalization;
24	using System.Text;
25	
26	using Microsoft.Extensions.Logging;
27	
28	using Quartz.Impl.Matchers;
29	using Quartz.Impl.Triggers;
30	using Quartz.Diagnostics;
31	using Quartz.Spi;
32	
33	namespace Quartz.Simpl;
34	
35	/// <summary>
36	/// This class implements a <see cref="IJobStore" /> that
37	/// utilizes RAM as its storage device.
38	/// <para>
39	/// As you should know, the ramification of this is that access is extremely
40	/// fast, but the data is completely volatile - therefore this <see cref="IJobStore" />
41	/// should not be used if true persistence between program shutdowns is
42	/// required.
43	/// </para>
44	/// </summary>
45	/// <author>James House</author>
46	/// <author>Sharada Jambula</author>
47	/// <author>Marko Lahma (.NET)</author>
48	public class RAMJobStore : IJobStore
49	{
50	    private readonly SemaphoreSlim lockObject = new(initialCount: 1, maxCount: 1);
51	
52	    private readonly ConcurrentDictionary<JobKey, JobWrapper> jobsByKey = [];
53	    private readonly ConcurrentDictionary<TriggerKey, TriggerWrapper> triggersByKey = new();
54	    private readonly Dictionary<string, Dictionary<JobKey, JobWrapper>> jobsByGroup = [];
55	    private readonly Dictionary<string, Dictionary<TriggerKey, TriggerWrapper>> triggersByGroup = [];
56	    private readonly SortedSet<TriggerWrapper> timeTriggers = new(new TriggerWrapperComparator());
57	    private readonly ConcurrentDictionary<string, ICalendar> calendarsByName = [];
58	    private readonly Dictionary<JobKey, List<TriggerWrapper>> triggersByJob = [];
59	    private readonly HashSet<string> pausedTriggerGroups = [];
60	    private readonly HashSet<string> pausedJobGroups = [];
61	    private readonly HashSet<JobKey> blockedJobs = [];
62	    private TimeSpan misfireThreshold = TimeSpan.FromSeconds(5);
63	    private ISchedulerSignaler signaler = null!;
64	    private TimeProvider timeProvider = TimeProvider.System;
65	    private readonly ILogger<RAMJobStore> logger;
66	
67	    /// <summary>
68	    /// Initializes a new instance of the <see cref="RAMJobStore"/> class.
69	    /// </summary>
70	    public RAMJobStore()
71	    {
72	        logger = LogProvider.CreateLogger<RAMJobStore>();
73	    }
74	
75	    /// <summary>
76	    /// Gets or sets the time by which a trigger must have missed its next-fire-time, in order for it to
77	    /// be considered "misfired" and thus have its misfire instruction applied.
78	    /// </summary>
79	    /// <value>
80	    /// The time by which a trigger must have missed its next-fire-time, in order for it to be considered
81	    /// "misfired" and thus have its misfire instruction applied. The default is <c>5</c> seconds.
82	    /// </value>
83	    /// <exception cref="ArgumentException"><paramref name="value"/> represents less than one millisecond.</exception>
84	    [TimeSpanParseRule(TimeSpanParseRule.Milliseconds)]
85	    public virtual TimeSpan MisfireThreshold
86	    {
87	        get => misfireThreshold;
88	        set
89	        {
90	            if (value.TotalMilliseconds < 1)
91	            {
92	                Throw.ArgumentException("MisfireThreshold must be larger than 0");
93	            }
94	            misfireThreshold = value;
95	        }
96	    }
97	
98	    private static long ftrCtr = TimeProvider.System.GetTimestamp();
99	
100	    /// <summary>
101	    /// Gets the fired trigger record id.
102	    /// </summary>
103	    /// <returns>The fired trigger record id.</returns>
104	    protected virtual string GetFiredTriggerRecordId()
105	    {
106	        long value = Interlocked.Increment(ref ftrCtr);
107	        return value.ToString(CultureInfo.InvariantCulture);
108	    }
109	
110	    /// <summary>
111	    /// Called by the QuartzScheduler before the <see cref="IJobStore" /> is
112	    /// used, in order to give it a chance to Initialize.
113	    /// </summary>
114	    public virtual ValueTask Initialize(ITypeLoadHelper loadHelper, ISchedulerSignaler signaler, CancellationToken cancellationToken = default)
115	    {
116	        this.signaler = signaler;
117	        logger.LogInformation("RAMJobStore initialized.");
118	        return default;
119	    }
120	
121	    /// <summary>
122	    /// Called by the QuartzScheduler to inform the <see cref="IJobStore" /> that
123	    /// the scheduler has started.
124	    /// </summary>
125	    public virtual ValueTask SchedulerStarted(CancellationToken cancellationToken = default)
126	    {
127	        // nothing to do
128	        return default;
129	    }
130	
131	    /// <summary>
132	    /// Called by the QuartzScheduler to inform the JobStore that
133	    /// the scheduler has been paused.
134	    /// </summary>
135	    public ValueTask SchedulerPaused(CancellationToken cancellationToken = default)
136	    {
137	        // nothing to do
138	        return default;
139	    }
140	
141	    /// <summary>
142	    /// Called by the QuartzScheduler to inform the JobStore that
143	    /// the scheduler has resumed after being paused.
144	    /// </summary>
145	    public ValueTask SchedulerResumed(CancellationToken cancellationToken = default)
146	    {
147	        // nothing to do
148	        return default;
149	    }
150	
151	    /// <summary>
152	    /// Called by the QuartzScheduler to inform the <see cref="IJobStore" /> that
153	    /// it should free up all of its resources because the scheduler is
154	    /// shutting down.
155	    /// </summary>
156	    public virtual ValueTask Shutdown(CancellationToken cancellationToken = default)
157	    {
158	        return default;
159	    }
160	
161	    /// <summary>
162	    /// Returns whether this instance supports persistence.
163	    /// </summary>
164	    /// <value></value>
165	    /// <returns></returns>
166	    public virtual bool SupportsPersistence => false;
167	
168	    /// <summary>
169	    /// Clears (deletes!) all scheduling data - all <see cref="IJob"/>s, <see cref="ITrigger" />s
170	    /// <see cref="ICalendar"/>s.
171	    /// </summary>
172	    public async ValueTask ClearAllSchedulingData(CancellationToken cancellationToken = default)
173	    {
174	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
175	        try
176	        {
177	            // unschedule jobs (delete triggers)
178	            foreach (string group in new List<string>(triggersByGroup.Keys))
179	            {
180	                var keys = GetTriggerKeysNoLock(GroupMatcher<TriggerKey>.GroupEquals(group));
181	                foreach (TriggerKey key in keys)
182	                {
183	                    await RemoveTriggerNoLock(key, removeOrphanedJob: true, cancellationToken).ConfigureAwait(false);
184	                }
185	            }
186	
187	            // delete jobs
188	            foreach (string group in new List<string>(jobsByGroup.Keys))
189	            {
190	                var keys = GetJobKeysNoLock(GroupMatcher<JobKey>.GroupEquals(group));
191	                foreach (JobKey key in keys)
192	                {
193	                    await RemoveJobNoLock(key, cancellationToken).ConfigureAwait(false);
194	                }
195	            }
196	
197	            // delete calendars
198	            foreach (string name in new List<string>(calendarsByName.Keys))
199	            {
200	                RemoveCalendarNoLock(name);
201	            }
202	        }
203	        finally
204	        {
205	            lockObject.Release();
206	        }
207	    }
208	
209	    /// <summary>
210	    /// Store the given <see cref="IJobDetail" /> and <see cref="ITrigger" />.
211	    /// </summary>
212	    /// <param name="job">The <see cref="IJobDetail" /> to be stored.</param>
213	    /// <param name="trigger">The <see cref="ITrigger" /> to be stored.</param>
214	    /// <param name="cancellationToken">The cancellation instruction.</param>
215	    public virtual async ValueTask StoreJobAndTrigger(IJobDetail job, IOperableTrigger trigger, CancellationToken cancellationToken = default)
216	    {
217	        await StoreJob(job, replaceExisting: false, cancellationToken).ConfigureAwait(false);
218	        await StoreTrigger(trigger, replaceExisting: false, cancellationToken).ConfigureAwait(false);
219	    }
220	
221	    /// <summary>
222	    /// Returns true if the given job group is paused.
223	    /// </summary>
224	    /// <param name="group">Job group name</param>
225	    /// <param name="cancellationToken">The cancellation instruction.</param>
226	    /// <returns></returns>
227	    public virtual async ValueTask<bool> IsJobGroupPaused(string group, CancellationToken cancellationToken = default)
228	    {
229	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
230	        try
231	        {
232	            return pausedJobGroups.Contains(group);
233	        }
234	        finally
235	        {
236	            lockObject.Release();
237	        }
238	    }
239	
240	    /// <summary>
241	    /// Returns true if the given TriggerGroup is paused.
242	    /// </summary>
243	    /// <returns></returns>
244	    public virtual async ValueTask<bool> IsTriggerGroupPaused(string group, CancellationToken cancellationToken = default)
245	    {
246	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
247	        try
248	        {
249	            return pausedTriggerGroups.Contains(group);
250	        }
251	        finally
252	        {
253	            lockObject.Release();
254	        }
255	    }
256	
257	    /// <summary>
258	    /// Store the given <see cref="IJob" />.
259	    /// </summary>
260	    /// <param name="job">The <see cref="IJob" /> to be stored.</param>
261	    /// <param name="replaceExisting">If <see langword="true" />, any <see cref="IJob" /> existing in the
262	    ///     <see cref="IJobStore" /> with the same name and group should be
263	    ///     over-written.</param>
264	    /// <param name="cancellationToken">The cancellation instruction.</param>
265	    public virtual async ValueTask StoreJob(IJobDetail job, bool replaceExisting, CancellationToken cancellationToken = default)
266	    {
267	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
268	        try
269	        {
270	            StoreJobNoLock(job, replaceExisting);
271	        }
272	        finally
273	        {
274	            lockObject.Release();
275	        }
276	    }
277	
278	    private void StoreJobNoLock(IJobDetail job, bool replaceExisting)
279	    {
280	        var jobKey = job.Key;
281	
282	        if (jobsByKey.TryGetValue(jobKey, out var originalJob))
283	        {
284	            if (!replaceExisting)
285	            {
286	                Throw.ObjectAlreadyExistsException(job);
287	            }
288	
289	            // update job detail
290	            originalJob.JobDetail = job.Clone();
291	        }
292	        else
293	        {
294	            // get job group
295	            if (!jobsByGroup.TryGetValue(jobKey.Group, out var grpMap))
296	            {
297	                grpMap = new Dictionary<JobKey, JobWrapper>();
298	                jobsByGroup[jobKey.Group] = grpMap;
299	            }
300	
301	            JobWrapper jw = new JobWrapper(job.Clone());
302	
303	            // add to jobs by group
304	            grpMap[jobKey] = jw;
305	            // add to jobs by FQN map
306	            jobsByKey[jobKey] = jw;
307	        }
308	    }
309	
310	    /// <summary>
311	    /// Remove (delete) the <see cref="IJob" /> with the given
312	    /// name, and any <see cref="ITrigger" /> s that reference
313	    /// it.
314	    /// </summary>
315	    /// <returns>
316	    /// 	<see langword="true" /> if a <see cref="IJob" /> with the given name and
317	    /// group was found and removed from the store.
318	    /// </returns>
319	    public virtual async ValueTask<bool> RemoveJob(JobKey jobKey, CancellationToken cancellationToken = default)
320	    {
321	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
322	        try
323	        {
324	            return await RemoveJobNoLock(jobKey, cancellationToken).ConfigureAwait(false);
325	        }
326	        finally
327	        {
328	            lockObject.Release();
329	        }
330	    }
331	
332	    private async ValueTask<bool> RemoveJobNoLock(JobKey jobKey, CancellationToken cancellationToken)
333	    {
334	        bool found = false;
335	        var triggersForJob = GetTriggerKeysForJobNoLock(jobKey);
336	        foreach (var key in triggersForJob)
337	        {
338	            await RemoveTriggerNoLock(key, removeOrphanedJob: true, cancellationToken).ConfigureAwait(false);
339	            found = true;
340	        }
341	
342	        found = jobsByKey.TryRemove(jobKey, out _) || found;
343	
344	        if (found)
345	        {
346	            if (jobsByGroup.TryGetValue(jobKey.Group, out var grpMap))
347	            {
348	                if (grpMap.Remove(jobKey) && grpMap.Count == 0)
349	                {
350	                    jobsByGroup.Remove(jobKey.Group);
351	                }
352	            }
353	        }
354	
355	        return found;
356	    }
357	
358	    public async ValueTask<bool> RemoveJobs(IReadOnlyCollection<JobKey> jobKeys, CancellationToken cancellationToken = default)
359	    {
360	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
361	        try
362	        {
363	            bool allFound = true;
364	            foreach (JobKey key in jobKeys)
365	            {
366	                allFound = await RemoveJobNoLock(key, cancellationToken).ConfigureAwait(false) && allFound;
367	            }
368	
369	            return allFound;
370	        }
371	        finally
372	        {
373	            lockObject.Release();
374	        }
375	    }
376	
377	    public async ValueTask<bool> RemoveTriggers(IReadOnlyCollection<TriggerKey> triggerKeys, CancellationToken cancellationToken = default)
378	    {
379	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
380	        try
381	        {
382	            bool allFound = true;
383	            foreach (TriggerKey key in triggerKeys)
384	            {
385	                allFound = await RemoveTriggerNoLock(key, removeOrphanedJob: true, cancellationToken).ConfigureAwait(false) && allFound;
386	            }
387	
388	            return allFound;
389	        }
390	        finally
391	        {
392	            lockObject.Release();
393	        }
394	    }
395	
396	    public async ValueTask StoreJobsAndTriggers(IReadOnlyDictionary<IJobDetail, IReadOnlyCollection<ITrigger>> triggersAndJobs, bool replace, CancellationToken cancellationToken = default)
397	    {
398	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
399	        try
400	        {
401	            // make sure there are no collisions...
402	            if (!replace)
403	            {
404	                foreach (var triggersByJob in triggersAndJobs)
405	                {
406	                    var job = triggersByJob.Key;
407	
408	                    if (jobsByKey.ContainsKey(job.Key))
409	                    {
410	                        Throw.ObjectAlreadyExistsException(job);
411	                    }
412	
413	                    foreach (ITrigger trigger in triggersByJob.Value)
414	                    {
415	                        if (triggersByKey.ContainsKey(trigger.Key))
416	                        {
417	                            Throw.ObjectAlreadyExistsException(trigger);
418	                        }
419	                    }
420	                }
421	            }
422	
423	            // do bulk add...
424	            foreach (var triggersByJob in triggersAndJobs)
425	            {
426	                StoreJobNoLock(triggersByJob.Key, replaceExisting: true);
427	                foreach (ITrigger trigger in triggersByJob.Value)
428	                {
429	                    await StoreTriggerNoLock((IOperableTrigger) trigger, replaceExisting: true, cancellationToken: cancellationToken).ConfigureAwait(false);
430	                }
431	            }
432	        }
433	        finally
434	        {
435	            lockObject.Release();
436	        }
437	    }
438	
439	    /// <summary>
440	    /// Remove (delete) the <see cref="ITrigger" /> with the
441	    /// given name.
442	    /// </summary>
443	    /// <returns>
444	    /// 	<see langword="true" /> if a <see cref="ITrigger" /> with the given
445	    /// name and group was found and removed from the store.
446	    /// </returns>
447	    public virtual ValueTask<bool> RemoveTrigger(TriggerKey triggerKey, CancellationToken cancellationToken = default)
448	    {
449	        return RemoveTrigger(triggerKey, removeOrphanedJob: true, cancellationToken);
450	    }
451	
452	    /// <summary>
453	    /// Store the given <see cref="ITrigger" />.
454	    /// </summary>
455	    /// <param name="trigger">The <see cref="ITrigger" /> to be stored.</param>
456	    /// <param name="replaceExisting">If <see langword="true" />, any <see cref="ITrigger" /> existing in
457	    ///     the <see cref="IJobStore" /> with the same name and group should
458	    ///     be over-written.</param>
