473	    private async Task StoreTriggerNoLock(IOperableTrigger trigger, bool replaceExisting, CancellationToken cancellationToken)
474	    {
475	        TriggerWrapper tw = new((IOperableTrigger) trigger.Clone());
476	        if (triggersByKey.ContainsKey(tw.TriggerKey))
477	        {
478	            if (!replaceExisting)
479	            {
480	                Throw.ObjectAlreadyExistsException(trigger);
481	            }
482	
483	            // don't delete orphaned job, this trigger has the job anyways
484	            await RemoveTriggerNoLock(tw.TriggerKey, removeOrphanedJob: false, cancellationToken).ConfigureAwait(false);
485	        }
486	
487	        if (!jobsByKey.ContainsKey(tw.JobKey))
488	        {
489	            Throw.JobPersistenceException($"The job ({tw.JobKey}) referenced by the trigger does not exist.");
490	        }
491	
492	        // add to triggers by job
493	        if (!triggersByJob.TryGetValue(tw.JobKey, out var jobList))
494	        {
495	            jobList = new List<TriggerWrapper>(1);
496	            triggersByJob.Add(tw.JobKey, jobList);
497	        }
498	
499	        jobList.Add(tw);
500	
501	        // add to triggers by group
502	        if (!triggersByGroup.TryGetValue(tw.TriggerKey.Group, out var grpMap))
503	        {
504	            grpMap = new Dictionary<TriggerKey, TriggerWrapper>();
505	            triggersByGroup[tw.TriggerKey.Group] = grpMap;
506	        }
507	
508	        grpMap[tw.TriggerKey] = tw;
509	        // add to triggers by FQN map
510	        triggersByKey[tw.TriggerKey] = tw;
511	
512	        if (pausedTriggerGroups.Contains(tw.TriggerKey.Group) || pausedJobGroups.Contains(tw.JobKey.Group))
513	        {
514	            tw.state = InternalTriggerState.Paused;
515	            if (blockedJobs.Contains(tw.JobKey))
516	            {
517	                tw.state = InternalTriggerState.PausedAndBlocked;
518	            }
519	        }
520	        else if (blockedJobs.Contains(tw.JobKey))
521	        {
522	            tw.state = InternalTriggerState.Blocked;
523	        }
524	        else
525	        {
526	            timeTriggers.Add(tw);
527	        }
528	    }
