532	    /// given name.
533	    ///
534	    /// </summary>
535	    /// <returns>
536	    /// 	<see langword="true" /> if a <see cref="ITrigger" /> with the given
537	    /// name and group was found and removed from the store.
538	    /// </returns>
539	    /// <param name="key">The <see cref="ITrigger" /> to be removed.</param>
540	    /// <param name="removeOrphanedJob">Whether to delete orphaned job details from scheduler if job becomes orphaned from removing the trigger.</param>
541	    /// <param name="cancellationToken"></param>
542	    protected virtual async ValueTask<bool> RemoveTrigger(TriggerKey key, bool removeOrphanedJob, CancellationToken cancellationToken)
543	    {
544	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
545	        try
546	        {
547	            return await RemoveTriggerNoLock(key, removeOrphanedJob, cancellationToken).ConfigureAwait(false);
548	        }
549	        finally
550	        {
551	            lockObject.Release();
552	        }
553	    }
