555	    private async Task<bool> RemoveTriggerNoLock(TriggerKey key, bool removeOrphanedJob, CancellationToken cancellationToken)
556	    {
557	        // remove from triggers by FQN map
558	        var found = triggersByKey.TryRemove(key, out var tw);
559	        if (tw is not null)
560	        {
561	            // remove from triggers by group
562	            if (triggersByGroup.TryGetValue(key.Group, out var grpMap))
563	            {
564	                if (grpMap.Remove(key) && grpMap.Count == 0)
565	                {
566	                    triggersByGroup.Remove(key.Group);
567	                }
568	            }
569	
570	            //remove from triggers by job
571	            if (triggersByJob.TryGetValue(tw.JobKey, out var jobList))
572	            {
573	                if (jobList.Remove(tw) && jobList.Count == 0)
574	                {
575	                    triggersByJob.Remove(tw.JobKey);
576	                }
577	            }
578	
579	            timeTriggers.Remove(tw);
580	
581	            if (removeOrphanedJob)
582	            {
583	                JobWrapper jw = jobsByKey[tw.JobKey];
584	                var triggerKeys = GetTriggerKeysForJobNoLock(tw.JobKey);
585	                if (triggerKeys.Length == 0 && !jw.JobDetail.Durable && await RemoveJobNoLock(jw.Key, cancellationToken).ConfigureAwait(false))
586	                {
587	                    await signaler.NotifySchedulerListenersJobDeleted(jw.Key, cancellationToken).ConfigureAwait(false);
588	                }
589	            }
590	        }
591	
592	        return found;
593	    }
