595	    /// <summary>
596	    /// Replaces the trigger.
597	    /// </summary>
598	    /// <param name="triggerKey">The <see cref="TriggerKey"/> of the <see cref="ITrigger" /> to be replaced.</param>
599	    /// <param name="trigger">The new trigger.</param>
600	    /// <param name="cancellationToken">The cancellation instruction.</param>
601	    public virtual async ValueTask<bool> ReplaceTrigger(TriggerKey triggerKey, IOperableTrigger trigger, CancellationToken cancellationToken = default)
602	    {
603	        bool found;
604	
605	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
606	        try
607	        {
608	            // remove from triggers by FQN map
609	            triggersByKey.TryRemove(triggerKey, out var tw);
610	            found = tw is not null;
611	
612	            if (found)
613	            {
614	                if (!tw!.JobKey.Equals(trigger.JobKey))
615	                {
616	                    Throw.JobPersistenceException("New trigger is not related to the same job as the old trigger.");
617	                }
618	
619	                // remove from triggers by group
620	                if (triggersByGroup.TryGetValue(triggerKey.Group, out var grpMap))
621	                {
622	                    if (grpMap.Remove(triggerKey) && grpMap.Count == 0)
623	                    {
624	                        triggersByGroup.Remove(triggerKey.Group);
625	                    }
626	                }
627	
628	                // remove from triggers by job
629	                if (triggersByJob.TryGetValue(tw.JobKey, out var jobList))
630	                {
631	                    if (jobList.Remove(tw) && jobList.Count == 0)
632	                    {
633	                        triggersByJob.Remove(tw.JobKey);
634	                    }
635	                }
636	
637	                timeTriggers.Remove(tw);
638	
639	                try
640	                {
641	                    await StoreTriggerNoLock(trigger, replaceExisting: false, cancellationToken: cancellationToken).ConfigureAwait(false);
642	                }
643	                catch (JobPersistenceException)
644	                {
645	                    // put previous trigger back...
646	                    await StoreTriggerNoLock(tw.Trigger, replaceExisting: false, cancellationToken: cancellationToken).ConfigureAwait(false);
647	                    throw;
648	                }
649	            }
650	        }
651	        finally
652	        {
653	            lockObject.Release();
654	        }
655	        return found;
656	    }
