1498	    private async ValueTask<List<string>> ResumeTriggersNoLock(GroupMatcher<TriggerKey> matcher)
1499	    {
1500	        var groups = new HashSet<string>();
1501	        var keys = GetTriggerKeysNoLock(matcher);
1502	
1503	        foreach (TriggerKey triggerKey in keys)
1504	        {
1505	            groups.Add(triggerKey.Group);
1506	            if (triggersByKey.TryGetValue(triggerKey, out var tw))
1507	            {
1508	                string jobGroup = tw.JobKey.Group;
1509	                if (pausedJobGroups.Contains(jobGroup))
1510	                {
1511	                    continue;
1512	                }
1513	            }
1514	
1515	            await ResumeTriggerNoLock(triggerKey).ConfigureAwait(false);
1516	        }
1517	
1518	        // Find all matching paused trigger groups, and then remove them.
1519	        StringOperator op = matcher.CompareWithOperator;
1520	        var pausedGroups = new List<string>();
1521	        var matcherGroup = matcher.CompareToValue;
1522	        if (StringOperator.Equality.Equals(op))
1523	        {
1524	            if (pausedTriggerGroups.Contains(matcherGroup))
1525	            {
1526	                pausedGroups.Add(matcher.CompareToValue);
1527	            }
1528	            else
1529	            {
1530	                foreach (string group in pausedTriggerGroups)
1531	                {
1532	                    if (op.Evaluate(group, matcherGroup))
1533	                    {
1534	                        pausedGroups.Add(group);
1535	                    }
1536	                }
1537	            }
1538	
1539	            foreach (string pausedGroup in pausedGroups)
1540	            {
1541	                pausedTriggerGroups.Remove(pausedGroup);
1542	            }
1543	        }
1544	
1545	        return [..groups];
1546	    }
