1676	    /// <summary>
1677	    /// Applies the misfire.
1678	    /// </summary>
1679	    /// <param name="tw">The trigger wrapper.</param>
1680	    /// <returns>
1681	    /// <see langword="true"/> if the next fire time of the trigger was updated from either
1682	    /// one value to another, or from a given value to <see langword="null"/>; otherwise,
1683	    /// <see langword="false"/>.
1684	    /// </returns>
1685	    private async ValueTask<bool> ApplyMisfireNoLock(TriggerWrapper tw)
1686	    {
1687	        if (tw.Trigger.MisfireInstruction == MisfireInstruction.IgnoreMisfirePolicy)
1688	        {
1689	            return false;
1690	        }
1691	
1692	        DateTimeOffset misfireTime = timeProvider.GetUtcNow();
1693	        if (MisfireThreshold > TimeSpan.Zero)
1694	        {
1695	            misfireTime = misfireTime.AddTicks(-1 * MisfireThreshold.Ticks);
1696	        }
1697	
1698	        DateTimeOffset? tnft = tw.Trigger.GetNextFireTimeUtc();
1699	        if (!tnft.HasValue || tnft.GetValueOrDefault() > misfireTime)
1700	        {
1701	            return false;
1702	        }
1703	
1704	        ICalendar? cal = null;
1705	        if (tw.Trigger.CalendarName is not null)
1706	        {
1707	            calendarsByName.TryGetValue(tw.Trigger.CalendarName, out cal);
1708	        }
1709	
1710	        await signaler.NotifyTriggerListenersMisfired(tw.Trigger.Clone()).ConfigureAwait(false);
1711	
1712	        // Save the original scheduled fire time before misfire handling changes it.
1713	        var originalFireTime = tw.Trigger.GetNextFireTimeUtc();
1714	        var now = timeProvider.GetUtcNow();
1715	
1716	        if (tw.Trigger is INextVersionTrigger nvt)
1717	        {
1718	            nvt.UpdateAfterMisfire(cal, MisfireThreshold);
1719	        }
1720	        else
1721	        {
1722	            tw.Trigger.UpdateAfterMisfire(cal);
1723	        }
1724	
1725	        // Only save for "fire now" misfire policies (FireOnceNow, FireNow, RescheduleNowWith*).
1726	        // These set nextFireTimeUtc to ~now. "Reschedule next" policies (DoNothing,
1727	        // RescheduleNextWith*) set it to a future schedule time where the existing code
1728	        // already produces the correct ScheduledFireTimeUtc.
1729	        var updatedTnft = tw.Trigger.GetNextFireTimeUtc();
1730	        if (tw.Trigger is AbstractTrigger abstractTrigger
1731	            && originalFireTime.HasValue && updatedTnft.HasValue
1732	            && originalFireTime.Value != updatedTnft.Value
1733	            && Math.Abs((updatedTnft.Value - now).TotalMilliseconds) < AbstractTrigger.FireNowMisfireDetectionThresholdMs)
1734	        {
1735	            abstractTrigger.MisfiredFromFireTimeUtc = originalFireTime;
1736	        }
1737	
1738	        if (!updatedTnft.HasValue)
1739	        {
1740	            tw.state = InternalTriggerState.Complete;
1741	            await signaler.NotifySchedulerListenersFinalized(tw.Trigger).ConfigureAwait(false);
1742	
1743	            // We do not remove the trigger that we applied the misfire for (since its next fire time has been
1744	            // updated). Instead we remove a trigger with the same trigger key, but with no next fire time set.
1745	            timeTriggers.Remove(tw);
1746	        }
1747	        else if (tnft.GetValueOrDefault() == updatedTnft.GetValueOrDefault())
1748	        {
1749	            return false;
1750	        }
1751	
1752	        return true;
1753	    }
