1757	    /// by the calling scheduler.
1758	    /// </summary>
1759	    /// <seealso cref="ITrigger" />
1760	    public virtual async ValueTask<List<IOperableTrigger>> AcquireNextTriggers(DateTimeOffset noLaterThan, int maxCount, TimeSpan timeWindow, CancellationToken cancellationToken = default)
1761	    {
1762	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
1763	        try
1764	        {
1765	            // return empty list if store has no triggers.
1766	            if (timeTriggers.Count == 0)
1767	            {
1768	                return [];
1769	            }
1770	
1771	            var result = new List<IOperableTrigger>();
1772	            var acquiredJobKeysForNoConcurrentExec = new HashSet<JobKey>();
1773	            var excludedTriggers = new HashSet<TriggerWrapper>();
1774	            DateTimeOffset batchEnd = noLaterThan;
1775	
1776	            while (true)
1777	            {
1778	                var tw = timeTriggers.Min;
1779	                if (tw is null)
1780	                {
1781	                    break;
1782	                }
1783	
1784	                // It would've been more efficient to only remove the trigger if we're really acquiring it, but
1785	                // we need to remove it before we apply the misfire. It not, after having updated the trigger,
1786	                // we'd attempt to remove the trigger with the new next fire time which would no longer match
1787	                // the trigger in the 'timeTriggers' set.
1788	                timeTriggers.Remove(tw);
1789	
1790	                // Use a local for the next fire time to reduce number of interface calls.
1791	                var tnft = tw.Trigger.GetNextFireTimeUtc();
1792	
1793	                // When the trigger is not scheduled to fire, continue with the next trigger.
1794	                if (!tnft.HasValue)
1795	                {
1796	                    continue;
1797	                }
1798	
1799	                if (await ApplyMisfireNoLock(tw).ConfigureAwait(false))
1800	                {
1801	                    // If - after applying the misfire policy - the trigger is still scheduled to fire, we'll
1802	                    // add it back to the set of triggers. We cannot use the "cached" next fire time here as
1803	                    // it has been updated in ApplyMisfire(TriggerWrapper tw).
1804	                    if (tw.Trigger.GetNextFireTimeUtc() is not null)
1805	                    {
1806	                        timeTriggers.Add(tw);
1807	                    }
1808	
1809	                    continue;
1810	                }
1811	
1812	                // The first trigger that is scheduled to fire after the window for the current batch completes
1813	                // the current batch.
1814	                if (tnft.GetValueOrDefault() > batchEnd)
1815	                {
1816	                    // Since we removed the trigger from 'timeTriggers' earlier, we now need to add it back.
1817	                    timeTriggers.Add(tw);
1818	                    break;
1819	                }
1820	
1821	                JobKey jobKey = tw.JobKey;
1822	                IJobDetail job = jobsByKey[jobKey].JobDetail;
1823	
1824	                // If trigger's job disallows concurrent execution and the job was already added to the result,
1825	                // then we'll add the trigger to the list of excluded triggers (which we'll add back to the set
1826	                // of time triggers after we've completed the current batch) and skip the trigger.
1827	                if (job.ConcurrentExecutionDisallowed)
1828	                {
1829	                    if (!acquiredJobKeysForNoConcurrentExec.Add(jobKey))
1830	                    {
1831	                        excludedTriggers.Add(tw);
1832	                        continue; // go to next trigger in store.
1833	                    }
1834	                }
1835	
1836	                tw.state = InternalTriggerState.Acquired;
1837	                tw.Trigger.FireInstanceId = GetFiredTriggerRecordId();
1838	                IOperableTrigger trig = (IOperableTrigger) tw.Trigger.Clone();
1839	
1840	                result.Add(trig);
1841	
1842	                if (result.Count == maxCount)
1843	                {
1844	                    break;
1845	                }
1846	
1847	                // Use the next fire time of the first acquired trigger to update the maximum next fire
1848	                // time that we accept for this batch. We only perform this update if we want to acquire
1849	                // more than one trigger.
1850	                if (result.Count == 1)
1851	                {
1852	                    var now = timeProvider.GetUtcNow();
1853	                    var nextFireTime = tnft.GetValueOrDefault();
1854	                    var max = now > nextFireTime ? now : nextFireTime;
1855	
1856	                    batchEnd = max + timeWindow;
1857	                }
1858	            }
1859	
1860	            // If we did excluded triggers to prevent ACQUIRE state due to DisallowConcurrentExecution, we need to add them back to store.
1861	            if (excludedTriggers.Count > 0)
1862	            {
1863	                foreach (var excludedTrigger in excludedTriggers)
1864	                {
1865	                    timeTriggers.Add(excludedTrigger);
1866	                }
1867	            }
1868	
1869	            return result;
1870	        }
1871	        finally
1872	        {
1873	            lockObject.Release();
1874	        }
1875	    }
1876	
1877	    /// <summary>
1878	    /// Inform the <see cref="IJobStore" /> that the scheduler no longer plans to
1879	    /// fire the given <see cref="ITrigger" />, that it had previously acquired
1880	    /// (reserved).
1881	    /// </summary>
1882	    public virtual async ValueTask ReleaseAcquiredTrigger(IOperableTrigger trigger, CancellationToken cancellationToken = default)
1883	    {
1884	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
1885	        try
1886	        {
1887	            if (triggersByKey.TryGetValue(trigger.Key, out var tw) && tw.state == InternalTriggerState.Acquired)
1888	            {
1889	                tw.state = InternalTriggerState.Waiting;
1890	                timeTriggers.Add(tw);
1891	            }
1892	        }
1893	        finally
1894	        {
1895	            lockObject.Release();
1896	        }
1897	    }
1898	
1899	    /// <summary>
1900	    /// Inform the <see cref="IJobStore" /> that the scheduler is now firing the
1901	    /// given <see cref="ITrigger" /> (executing its associated <see cref="IJob" />),
1902	    /// that it had previously acquired (reserved).
1903	    /// </summary>
1904	    public virtual async ValueTask<List<TriggerFiredResult>> TriggersFired(IReadOnlyCollection<IOperableTrigger> triggers, CancellationToken cancellationToken = default)
1905	    {
1906	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
1907	        try
1908	        {
1909	            List<TriggerFiredResult> results = new(triggers.Count);
1910	
1911	            foreach (IOperableTrigger trigger in triggers)
1912	            {
1913	                // was the trigger deleted since being acquired?
1914	                if (!triggersByKey.TryGetValue(trigger.Key, out var tw))
1915	                {
1916	                    results.Add(new TriggerFiredResult((TriggerFiredBundle?) null));
1917	                    continue;
1918	                }
1919	
1920	                // was the trigger completed, paused, blocked, etc. since being acquired?
1921	                if (tw.state != InternalTriggerState.Acquired)
1922	                {
1923	                    results.Add(new TriggerFiredResult((TriggerFiredBundle?) null));
1924	                    continue;
1925	                }
1926	
1927	                ICalendar? cal = null;
1928	                if (tw.Trigger.CalendarName is not null)
1929	                {
1930	                    calendarsByName.TryGetValue(tw.Trigger.CalendarName, out cal);
1931	                    if (cal is null)
1932	                    {
1933	                        results.Add(new TriggerFiredResult((TriggerFiredBundle?) null));
1934	                        continue;
1935	                    }
1936	                }
1937	
1938	                DateTimeOffset? prevFireTime = trigger.GetPreviousFireTimeUtc();
1939	
1940	                // Read saved original fire time (set during ApplyMisfireNoLock if a misfire occurred)
1941	                DateTimeOffset? scheduledFireTime = null;
1942	                if (trigger is AbstractTrigger at)
1943	                {
1944	                    scheduledFireTime = at.MisfiredFromFireTimeUtc;
1945	                    at.MisfiredFromFireTimeUtc = null;
1946	                }
1947	                if (tw.Trigger is AbstractTrigger twAt)
1948	                {
1949	                    twAt.MisfiredFromFireTimeUtc = null;
1950	                }
1951	
1952	                // in case trigger was replaced between acquiring and firing
1953	                timeTriggers.Remove(tw);
1954	                // call triggered on our copy, and the scheduler's copy
1955	                tw.Trigger.Triggered(cal);
1956	                trigger.Triggered(cal);
1957	                //tw.state = TriggerWrapper.STATE_EXECUTING;
1958	                tw.state = InternalTriggerState.Waiting;
1959	
1960	                var jobDetail = jobsByKey[trigger.JobKey].JobDetail.Clone();
1961	                TriggerFiredBundle bndle = new TriggerFiredBundle(
1962	                    jobDetail,
1963	                    trigger,
1964	                    cal,
1965	                    jobIsRecovering: false,
1966	                    timeProvider.GetUtcNow(),
1967	                    scheduledFireTime ?? trigger.GetPreviousFireTimeUtc(),
1968	                    prevFireTime,
1969	                    trigger.GetNextFireTimeUtc());
1970	
1971	                IJobDetail job = bndle.JobDetail;
1972	
1973	                if (job.ConcurrentExecutionDisallowed)
1974	                {
1975	                    var triggerWrappersForJob = GetTriggerWrappersForJobNoLock(job.Key);
1976	
1977	                    for (var i = 0; i < triggerWrappersForJob.Count; i++)
1978	                    {
1979	                        var ttw = triggerWrappersForJob[i];
1980	
1981	                        if (ttw.state == InternalTriggerState.Waiting)
1982	                        {
1983	                            ttw.state = InternalTriggerState.Blocked;
1984	                        }
1985	
1986	                        if (ttw.state == InternalTriggerState.Paused)
1987	                        {
1988	                            ttw.state = InternalTriggerState.PausedAndBlocked;
1989	                        }
1990	
1991	                        timeTriggers.Remove(ttw);
1992	                    }
1993	
1994	                    blockedJobs.Add(job.Key);
1995	                }
1996	                else if (tw.Trigger.GetNextFireTimeUtc() is not null)
1997	                {
1998	                    timeTriggers.Add(tw);
1999	                }
2000	
2001	                results.Add(new TriggerFiredResult(bndle));
2002	            }
2003	
2004	            return results;
2005	        }
2006	        finally
2007	        {
2008	            lockObject.Release();
2009	        }
2010	    }
2011	
2012	    /// <summary>
2013	    /// Inform the <see cref="IJobStore" /> that the scheduler has completed the
2014	    /// firing of the given <see cref="ITrigger" /> (and the execution its
2015	    /// associated <see cref="IJob" />), and that the <see cref="JobDataMap" />
2016	    /// in the given <see cref="IJobDetail" /> should be updated if the <see cref="IJob" />
2017	    /// is stateful.
2018	    /// </summary>
2019	    public virtual async ValueTask TriggeredJobComplete(IOperableTrigger trigger, IJobDetail jobDetail, SchedulerInstruction triggerInstCode, CancellationToken cancellationToken = default)
2020	    {
2021	        await lockObject.WaitAsync(cancellationToken).ConfigureAwait(false);
2022	        try
2023	        {
2024	            // It's possible that the job is null if:
2025	            //   1- it was deleted during execution
2026	            //   2- RAMJobStore is being used only for volatile jobs / triggers
2027	            //      from the JDBC job store
2028	
2029	            if (jobsByKey.TryGetValue(jobDetail.Key, out var jw))
2030	            {
2031	                IJobDetail jd = jw.JobDetail;
2032	
2033	                if (jobDetail.PersistJobDataAfterExecution)
2034	                {
2035	                    JobDataMap newData = jobDetail.JobDataMap;
2036	                    newData = (JobDataMap) newData.Clone();
2037	                    newData.ClearDirtyFlag();
2038	                    jd = jd.GetJobBuilder().SetJobData(newData).Build();
2039	                    jw.JobDetail = jd;
2040	                }
2041	
2042	                if (jd.ConcurrentExecutionDisallowed)
2043	                {
2044	                    blockedJobs.Remove(jd.Key);
2045	
2046	                    var triggerWrappersForJob = GetTriggerWrappersForJobNoLock(jd.Key);
2047	
2048	                    for (var i = 0; i < triggerWrappersForJob.Count; i++)
2049	                    {
2050	                        var ttw = triggerWrappersForJob[i];
2051	
2052	                        if (ttw.state == InternalTriggerState.Blocked)
2053	                        {
2054	                            ttw.state = InternalTriggerState.Waiting;
2055	                            timeTriggers.Add(ttw);
2056	                        }
2057	
2058	                        if (ttw.state == InternalTriggerState.PausedAndBlocked)
2059	                        {
2060	                            ttw.state = InternalTriggerState.Paused;
2061	                        }
2062	                    }
2063	
2064	                    await signaler.SignalSchedulingChange(candidateNewNextFireTimeUtc: null, cancellationToken).ConfigureAwait(false);
2065	                }
2066	            }
2067	            else
2068	            {
2069	                // even if it was deleted, there may be cleanup to do
2070	                blockedJobs.Remove(jobDetail.Key);
2071	            }
2072	
2073	            // check for trigger deleted during execution...
2074	            if (triggersByKey.TryGetValue(trigger.Key, out var tw))
2075	            {
2076	                if (triggerInstCode == SchedulerInstruction.DeleteTrigger)
2077	                {
2078	                    logger.LogDebug("Deleting trigger");
2079	                    DateTimeOffset? d = trigger.GetNextFireTimeUtc();
2080	                    if (!d.HasValue)
2081	                    {
2082	                        // double check for possible reschedule within job
2083	                        // execution, which would cancel the need to delete...
2084	                        d = tw.Trigger.GetNextFireTimeUtc();
2085	                        if (!d.HasValue)
2086	                        {
2087	                            await RemoveTriggerNoLock(trigger.Key, removeOrphanedJob: true, cancellationToken).ConfigureAwait(false);
2088	                        }
2089	                        else
2090	                        {
2091	                            logger.LogDebug("Deleting cancelled - trigger still active");
2092	                        }
2093	                    }
2094	                    else
2095	                    {
2096	                        await RemoveTriggerNoLock(trigger.Key, removeOrphanedJob: true, cancellationToken).ConfigureAwait(false);
2097	                        await signaler.SignalSchedulingChange(candidateNewNextFireTimeUtc: null, cancellationToken).ConfigureAwait(false);
2098	                    }
2099	                }
2100	                else if (triggerInstCode == SchedulerInstruction.SetTriggerComplete)
2101	                {
2102	                    tw.state = InternalTriggerState.Complete;
2103	                    timeTriggers.Remove(tw);
2104	                    await signaler.SignalSchedulingChange(candidateNewNextFireTimeUtc: null, cancellationToken).ConfigureAwait(false);
2105	                }
2106	                else if (triggerInstCode == SchedulerInstruction.SetTriggerError)
2107	                {
2108	                    logger.LogInformation("Trigger {TriggerKey} set to ERROR state.", trigger.Key);
2109	                    tw.state = InternalTriggerState.Error;
2110	                    await signaler.SignalSchedulingChange(candidateNewNextFireTimeUtc: null, cancellationToken).ConfigureAwait(false);
2111	                }
2112	                else if (triggerInstCode == SchedulerInstruction.SetAllJobTriggersError)
2113	                {
2114	                    logger.LogInformation("All triggers of Job {JobKey} set to ERROR state.", trigger.JobKey);
2115	                    SetAllTriggersOfJobToState(trigger.JobKey, InternalTriggerState.Error);
2116	                    await signaler.SignalSchedulingChange(candidateNewNextFireTimeUtc: null, cancellationToken).ConfigureAwait(false);
2117	                }
2118	                else if (triggerInstCode == SchedulerInstruction.SetAllJobTriggersComplete)
2119	                {
2120	                    SetAllTriggersOfJobToState(trigger.JobKey, InternalTriggerState.Complete);
2121	                    await signaler.SignalSchedulingChange(candidateNewNextFireTimeUtc: null, cancellationToken).ConfigureAwait(false);
2122	                }
2123	            }
2124	        }
2125	        finally
2126	        {
2127	            lockObject.Release();
2128	        }
2129	    }
2130	
2131	    /// <summary>
2132	    /// Inform the <see cref="IJobStore" /> of the Scheduler instance's Id,
2133	    /// prior to initialize being invoked.
2134	    /// </summary>
2135	    string IJobStore.InstanceId
2136	    {
2137	        set { }
2138	    }
2139	
2140	    /// <summary>
2141	    /// Inform the <see cref="IJobStore" /> of the Scheduler instance's name,
2142	    /// prior to initialize being invoked.
2143	    /// </summary>
2144	    string IJobStore.InstanceName
2145	    {
2146	        set { }
2147	    }
2148	
2149	    int IJobStore.ThreadPoolSize
2150	    {
2151	        set { }
2152	    }
2153	
2154	    TimeProvider IJobStore.TimeProvider
2155	    {
2156	        set => timeProvider = value;
2157	    }
2158	
2159	    public long EstimatedTimeToReleaseAndAcquireTrigger => 5;
2160	
2161	    public bool Clustered => false;
2162	
2163	    public virtual TimeSpan GetAcquireRetryDelay(int failureCount) => TimeSpan.FromMilliseconds(20);
2164	
2165	    /// <summary>
2166	    /// Sets the state of all triggers of job to specified state.
2167	    /// </summary>
2168	    /// <remarks>
2169	    /// This method should only be executed while holding the instance level lock.
2170	    /// </remarks>
2171	    protected virtual void SetAllTriggersOfJobToState(JobKey jobKey, InternalTriggerState state)
2172	    {
2173	        var triggerWrappersForJob = GetTriggerWrappersForJobNoLock(jobKey);
2174	
2175	        for (var i = 0; i < triggerWrappersForJob.Count; i++)
2176	        {
2177	            var tw = triggerWrappersForJob[i];
2178	
2179	            tw.state = state;
2180	            if (state != InternalTriggerState.Waiting)
2181	            {
2182	                timeTriggers.Remove(tw);
2183	            }
2184	        }
2185	    }
2186	
2187	    /// <summary>
2188	    /// Peeks the triggers.
2189	    /// </summary>
2190	    /// <returns></returns>
2191	    internal async ValueTask<string> PeekTriggers()
2192	    {
2193	        StringBuilder str = new StringBuilder();
2194	
2195	        await lockObject.WaitAsync().ConfigureAwait(false);
2196	        try
2197	        {
2198	            foreach (TriggerWrapper tw in triggersByKey.Values)
2199	            {
2200	                str.Append(tw.Trigger.Key.Name);
2201	                str.Append('/');
2202	            }
2203	
2204	            str.Append(" | ");
2205	
2206	            foreach (TriggerWrapper tw in timeTriggers)
2207	            {
2208	                str.Append(tw.Trigger.Key.Name);
2209	                str.Append("->");
2210	            }
2211	        }
2212	        finally
2213	        {
2214	            lockObject.Release();
2215	        }
2216	
2217	        return str.ToString();
2218	    }
2219	
