35	/// <summary>
36	/// JobRunShell instances are responsible for providing the 'safe' environment
37	/// for <see cref="IJob" /> s to run in, and for performing all of the work of
38	/// executing the <see cref="IJob" />, catching ANY thrown exceptions, updating
39	/// the <see cref="ITrigger" /> with the <see cref="IJob" />'s completion code,
40	/// etc.
41	/// <para>
42	/// A <see cref="JobRunShell" /> instance is created by a <see cref="IJobRunShellFactory" />
43	/// on behalf of the <see cref="QuartzSchedulerThread" /> which then runs the
44	/// shell in a thread from the configured thread pool when the
45	/// scheduler determines that a <see cref="IJob" /> has been triggered.
46	/// </para>
47	/// </summary>
48	/// <seealso cref="IJobRunShellFactory" />
49	/// <seealso cref="QuartzSchedulerThread" />
50	/// <seealso cref="IJob" />
51	/// <seealso cref="ITrigger" />
52	/// <author>James House</author>
53	/// <author>Marko Lahma (.NET)</author>
54	public class JobRunShell : SchedulerListenerSupport
55	{
56	    private readonly ILogger<JobRunShell> logger;
57	
58	    private JobExecutionContextImpl? jec;
59	    private QuartzScheduler? qs;
60	    private readonly IScheduler scheduler;
61	    private readonly TriggerFiredBundle firedTriggerBundle;
62	
63	    /// <summary>
64	    /// Create a JobRunShell instance with the given settings.
65	    /// </summary>
66	    /// <param name="scheduler">The <see cref="IScheduler" /> instance that should be made
67	    /// available within the <see cref="IJobExecutionContext" />.</param>
68	    /// <param name="bundle"></param>
69	    public JobRunShell(IScheduler scheduler, TriggerFiredBundle bundle)
70	    {
71	        this.scheduler = scheduler;
72	        firedTriggerBundle = bundle;
73	        logger = LogProvider.CreateLogger<JobRunShell>();
74	    }
75	
76	    public override ValueTask SchedulerShuttingdown(CancellationToken cancellationToken = default)
77	    {
78	        RequestShutdown();
79	        return default;
80	    }
81	
82	    /// <summary>
83	    /// Initializes the job execution context with given scheduler and bundle.
84	    /// </summary>
85	    /// <remarks>
86	    /// Job creation via <see cref="IJobFactory.NewJob"/> is deferred to <see cref="Run"/>
87	    /// so that AsyncLocal values set during job factory creation flow correctly to <see cref="IJob.Execute"/>.
88	    /// </remarks>
89	    /// <param name="sched">The scheduler.</param>
90	    /// <param name="cancellationToken">The cancellation instruction.</param>
91	    public virtual Task Initialize(
92	        QuartzScheduler sched,
93	        CancellationToken cancellationToken = default)
94	    {
95	        qs = sched;
96	        return Task.CompletedTask;
97	    }
98	
99	    /// <summary>
100	    /// Requests the Shutdown.
101	    /// </summary>
102	    public virtual void RequestShutdown()
103	    {
104	    }
105	
106	    /// <summary>
107	    /// This method has to be implemented in order that starting of the thread causes the object's
108	    /// run method to be called in that separately executing thread.
109	    /// </summary>
110	    /// <param name="cancellationToken">The cancellation instruction.</param>
111	    public virtual async Task Run(CancellationToken cancellationToken = default)
112	    {
113	        Context.CallerId.Value = Guid.NewGuid();
114	
115	        // Create the job here (moved from Initialize) so that AsyncLocal values
116	        // set during IJobFactory.NewJob flow correctly to IJob.Execute (#1528)
117	        IJobDetail jobDetail = firedTriggerBundle.JobDetail;
118	        IJob job;
119	        try
120	        {
121	            job = qs!.JobFactory.NewJob(firedTriggerBundle, scheduler);
122	            jec = new JobExecutionContextImpl(scheduler, firedTriggerBundle, job);
123	        }
124	        catch (SchedulerException se)
125	        {
126	            await qs!.NotifySchedulerListenersError($"An error occurred instantiating job to be executed. job='{jobDetail.Key}'", se, cancellationToken).ConfigureAwait(false);
127	
128	            IOperableTrigger errorTrigger = (IOperableTrigger) firedTriggerBundle.Trigger;
129	            SchedulerInstruction instruction = se.InnerException is ObjectDisposedException or OperationCanceledException
130	                ? SchedulerInstruction.NoInstruction
131	                : SchedulerInstruction.SetAllJobTriggersError;
132	            await qs.NotifyJobStoreJobComplete(errorTrigger, jobDetail, instruction, cancellationToken).ConfigureAwait(false);
133	            return;
134	        }
135	        catch (Exception e)
136	        {
137	            SchedulerException se = new SchedulerException($"Problem instantiating type '{jobDetail.JobType.FullName}: {e.Message}'", e);
138	            await qs!.NotifySchedulerListenersError($"An error occurred instantiating job to be executed. job='{jobDetail.Key}', message='{e.Message}'", se, cancellationToken).ConfigureAwait(false);
139	
140	            IOperableTrigger errorTrigger = (IOperableTrigger) firedTriggerBundle.Trigger;
141	            SchedulerInstruction instruction = e is ObjectDisposedException or OperationCanceledException
142	                ? SchedulerInstruction.NoInstruction
143	                : SchedulerInstruction.SetAllJobTriggersError;
144	            await qs.NotifyJobStoreJobComplete(errorTrigger, jobDetail, instruction, cancellationToken).ConfigureAwait(false);
145	            return;
146	        }
147	
148	        qs!.AddInternalSchedulerListener(this);
149	
150	        try
151	        {
152	            IOperableTrigger trigger = (IOperableTrigger) jec!.Trigger;
153	            do
154	            {
155	                JobExecutionException? jobExEx = null;
156	
157	                try
158	                {
159	                    Begin();
160	                }
161	                catch (SchedulerException se)
162	                {
163	                    string msg = $"Error executing Job {jec.JobDetail.Key}: couldn't begin execution.";
164	                    await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
165	                    await qs.NotifyJobStoreJobComplete(trigger, jobDetail, SchedulerInstruction.NoInstruction, cancellationToken).ConfigureAwait(false);
166	                    break;
167	                }
168	
169	                // notify job & trigger listeners...
170	                SchedulerInstruction instCode;
171	                try
172	                {
173	                    if (!await NotifyListenersBeginning(jec, cancellationToken).ConfigureAwait(false))
174	                    {
175	                        await qs.NotifyJobStoreJobComplete(trigger, jobDetail, SchedulerInstruction.NoInstruction, cancellationToken).ConfigureAwait(false);
176	                        break;
177	                    }
178	                }
179	                catch (VetoedException)
180	                {
181	                    try
182	                    {
183	                        instCode = trigger.ExecutionComplete(jec, result: null);
184	                        await qs.NotifyJobStoreJobVetoed(trigger, jobDetail, instCode, cancellationToken).ConfigureAwait(false);
185	
186	                        // Even if trigger got vetoed, we still needs to check to see if it's the trigger's finalized run or not.
187	                        if (!trigger.GetMayFireAgain())
188	                        {
189	                            await qs.NotifySchedulerListenersFinalized(jec.Trigger, cancellationToken).ConfigureAwait(false);
190	                        }
191	                        Complete(successfulExecution: true);
192	                    }
193	                    catch (SchedulerException se)
194	                    {
195	                        string msg = $"Error during veto of Job {jec.JobDetail.Key}: couldn't finalize execution.";
196	                        await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
197	                    }
198	                    break;
199	                }
200	
201	                if (logger.IsEnabled(LogLevel.Debug))
202	                {
203	                    logger.LogDebug("Calling Execute on job {JobKey}", jobDetail.Key);
204	                }
205	
206	                TimeProvider timeProvider = qs.resources.TimeProvider;
207	                long startTimestamp = timeProvider.GetTimestamp();
208	                long endTimestamp;
209	
210	                StartedActivity activity = QuartzActivitySource.StartJobExecute(jec, timeProvider.GetUtcNow());
211	                Instrumentation instrumentation = Meters.StartJobExecute(jec);
212	
213	
214	                // Execute the job
215	                try
216	                {
217	                    await job.Execute(jec).ConfigureAwait(false);
218	                    endTimestamp = timeProvider.GetTimestamp();
219	                }
220	                catch (OperationCanceledException) when (jec.CancellationToken.IsCancellationRequested)
221	                {
222	                    endTimestamp = timeProvider.GetTimestamp();
223	                    logger.LogInformation("Job {JobDetailKey} was cancelled", jobDetail.Key);
224	                }
225	                catch (JobExecutionException jee)
226	                {
227	                    endTimestamp = timeProvider.GetTimestamp();
228	                    jee.JobDetail = jobDetail;
229	                    jobExEx = jee;
230	                    logger.LogError(jee, "Job {JobDetailKey} threw a JobExecutionException: ", jobDetail.Key);
231	                }
232	                catch (Exception e)
233	                {
234	                    endTimestamp = timeProvider.GetTimestamp();
235	                    logger.LogError(e, "Job {JobDetailKey} threw an unhandled Exception: ", jobDetail.Key);
236	                    SchedulerException se = new JobExecutionProcessException(jec, e);
237	                    await qs.NotifySchedulerListenersError($"Job {jec.JobDetail.Key} threw an exception.", se, cancellationToken).ConfigureAwait(false);
238	                    jobExEx = new JobExecutionException(se, refireImmediately: false);
239	                    jobExEx.JobDetail = jobDetail;
240	                }
241	
242	                jec.JobRunTime = timeProvider.GetElapsedTime(startTimestamp, endTimestamp);
243	
244	                activity.Stop(timeProvider.GetUtcNow(), jobExEx);
245	                instrumentation.EndJobExecute(jec.JobRunTime, jobExEx);
246	
247	                // notify all job listeners
248	                if (!await NotifyJobListenersComplete(qs, jec, jobExEx, cancellationToken).ConfigureAwait(false))
249	                {
250	                    var failureInstCode = SchedulerInstruction.NoInstruction;
251	
252	                    // update the trigger to determine the correct instruction, even when listener notification fails
253	                    try
254	                    {
255	                        failureInstCode = trigger.ExecutionComplete(jec, jobExEx);
256	                        if (logger.IsEnabled(LogLevel.Debug))
257	                        {
258	                            logger.LogDebug("Trigger instruction : {InstCode}", failureInstCode);
259	                        }
260	                    }
261	                    catch (Exception e)
262	                    {
263	                        // If this happens, there's a bug in the trigger...
264	                        SchedulerException se = new SchedulerException("Trigger threw an unhandled exception.", e);
265	                        await qs.NotifySchedulerListenersError("Please report this error to the Quartz developers.", se, cancellationToken).ConfigureAwait(false);
266	                    }
267	
268	                    await qs.NotifyJobStoreJobComplete(trigger, jobDetail, failureInstCode, cancellationToken).ConfigureAwait(false);
269	                    break;
270	                }
271	
272	                instCode = SchedulerInstruction.NoInstruction;
273	
274	                // update the trigger
275	                try
276	                {
277	                    instCode = trigger.ExecutionComplete(jec, jobExEx);
278	                    if (logger.IsEnabled(LogLevel.Debug))
279	                    {
280	                        logger.LogDebug("Trigger instruction : {InstCode}", instCode);
281	                    }
282	                }
283	                catch (Exception e)
284	                {
285	                    // If this happens, there's a bug in the trigger...
286	                    SchedulerException se = new SchedulerException("Trigger threw an unhandled exception.", e);
287	                    await qs.NotifySchedulerListenersError("Please report this error to the Quartz developers.", se, cancellationToken).ConfigureAwait(false);
288	                }
289	
290	                // notify all trigger listeners
291	                if (!await NotifyTriggerListenersComplete(qs, jec, instCode, cancellationToken).ConfigureAwait(false))
292	                {
293	                    // Ensure finalized notification is still sent when the trigger has no next fire time,
294	                    // even if trigger listener notification failed.
295	                    try
296	                    {
297	                        if (!trigger.GetMayFireAgain())
298	                        {
299	                            await qs.NotifySchedulerListenersFinalized(jec.Trigger, cancellationToken).ConfigureAwait(false);
300	                        }
301	                    }
302	                    catch (Exception e)
303	                    {
304	                        SchedulerException se2 = new SchedulerException("Error notifying scheduler listeners of finalized trigger.", e);
305	                        await qs.NotifySchedulerListenersError("Error notifying scheduler listeners of finalized trigger.", se2, cancellationToken).ConfigureAwait(false);
306	                    }
307	
308	                    await qs.NotifyJobStoreJobComplete(trigger, jobDetail, instCode, cancellationToken).ConfigureAwait(false);
309	                    break;
310	                }
311	                // update job/trigger or re-Execute job
312	                if (instCode == SchedulerInstruction.ReExecuteJob)
313	                {
314	                    if (logger.IsEnabled(LogLevel.Debug))
315	                    {
316	                        logger.LogDebug("Rescheduling trigger to reexecute");
317	                    }
318	                    jec.IncrementRefireCount();
319	                    try
320	                    {
321	                        Complete(successfulExecution: false);
322	                    }
323	                    catch (SchedulerException se)
324	                    {
325	                        await qs.NotifySchedulerListenersError($"Error executing Job {jec.JobDetail.Key}: couldn't finalize execution.", se, cancellationToken).ConfigureAwait(false);
326	                    }
327	                    continue;
328	                }
329	
330	                try
331	                {
332	                    Complete(successfulExecution: true);
333	                }
334	                catch (SchedulerException se)
335	                {
336	                    await qs.NotifySchedulerListenersError($"Error executing Job {jec.JobDetail.Key}: couldn't finalize execution.", se, cancellationToken).ConfigureAwait(false);
337	                    continue;
338	                }
339	
340	                await qs.NotifyJobStoreJobComplete(trigger, jobDetail, instCode, cancellationToken).ConfigureAwait(false);
341	
342	                break;
343	            } while (true);
344	        }
345	        finally
346	        {
347	            qs.RemoveInternalSchedulerListener(this);
348	            await qs.JobFactory.ReturnJob(job).ConfigureAwait(false);
349	            jec.Dispose();
350	        }
351	    }
352	
353	    /// <summary>
354	    /// Runs begin procedures on this instance.
355	    /// </summary>
356	    protected virtual void Begin()
357	    {
358	    }
359	
360	    /// <summary>
361	    /// Completes the execution.
362	    /// </summary>
363	    /// <param name="successfulExecution">if set to <c>true</c> [successful execution].</param>
364	    protected virtual void Complete(bool successfulExecution)
365	    {
366	    }
367	
368	    /// <summary>
369	    /// Passivates this instance.
370	    /// </summary>
371	    public virtual void Passivate()
372	    {
373	        jec = null;
374	        qs = null;
375	    }
376	
377	    private async ValueTask<bool> NotifyListenersBeginning(
378	        JobExecutionContextImpl ctx,
379	        CancellationToken cancellationToken = default)
380	    {
381	        bool vetoed;
382	
383	        // notify all trigger listeners
384	        try
385	        {
386	            vetoed = await qs!.NotifyTriggerListenersFired(ctx, cancellationToken).ConfigureAwait(false);
387	        }
388	        catch (SchedulerException se)
389	        {
390	            var msg = $"Unable to notify TriggerListener(s) while firing trigger (Trigger and Job will NOT be fired!). trigger= {ctx.Trigger.Key} job= {ctx.JobDetail.Key}";
391	            await qs!.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
392	            return false;
393	        }
394	
395	        if (vetoed)
396	        {
397	            try
398	            {
399	                using Activity? activity = QuartzActivitySource.Instance.StartActivity(OperationName.Job.Veto);
400	                activity?.EnrichFrom(ctx);
401	
402	                await qs.NotifyJobListenersWasVetoed(ctx, cancellationToken).ConfigureAwait(false);
403	            }
404	            catch (SchedulerException se)
405	            {
406	                var msg = $"Unable to notify JobListener(s) of vetoed execution while firing trigger (Trigger and Job will NOT be fired!). trigger= {ctx.Trigger.Key} job= {ctx.JobDetail.Key}";
407	                await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
408	            }
409	            throw new VetoedException(this);
410	        }
411	
412	        // notify all job listeners
413	        try
414	        {
415	            await qs.NotifyJobListenersToBeExecuted(ctx, cancellationToken).ConfigureAwait(false);
416	        }
417	        catch (SchedulerException se)
418	        {
419	            string msg = $"Unable to notify JobListener(s) of Job to be executed: (Job will NOT be executed!). trigger= {ctx.Trigger.Key} job= {ctx.JobDetail.Key}";
420	            await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
421	
422	            return false;
423	        }
424	
425	        return true;
426	    }
427	
428	    private static async ValueTask<bool> NotifyJobListenersComplete(QuartzScheduler qs,
429	        JobExecutionContextImpl ctx,
430	        JobExecutionException? jobExEx,
431	        CancellationToken cancellationToken = default)
432	    {
433	        try
434	        {
435	            await qs.NotifyJobListenersWasExecuted(ctx, jobExEx, cancellationToken).ConfigureAwait(false);
436	        }
437	        catch (SchedulerException se)
438	        {
439	            string msg = $"Unable to notify JobListener(s) of Job that was executed: (error will be ignored). trigger= {ctx.Trigger.Key} job= {ctx.JobDetail.Key}";
440	            await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
441	
442	            return false;
443	        }
444	
445	        return true;
446	    }
447	
448	    private static ValueTask<bool> NotifyTriggerListenersComplete(QuartzScheduler qs,
449	        JobExecutionContextImpl ctx,
450	        SchedulerInstruction instCode,
451	        CancellationToken cancellationToken = default)
452	    {
453	        // check if we can do quick path
454	        if (ctx.Trigger.GetMayFireAgain())
455	        {
456	            try
457	            {
458	                var task = qs.NotifyTriggerListenersComplete(ctx, instCode, cancellationToken);
459	                return task.IsCompletedSuccessfully ? new ValueTask<bool>(true) : DoNotify(task, qs, ctx, cancellationToken);
460	            }
461	            catch (SchedulerException se)
462	            {
463	                return NotifyError(se, qs, ctx, cancellationToken);
464	            }
465	        }
466	
467	        return NotifyAwaited(qs, ctx, instCode, cancellationToken);
468	
469	        static async ValueTask<bool> NotifyAwaited(QuartzScheduler qs,
470	            JobExecutionContextImpl ctx,
471	            SchedulerInstruction instCode,
472	            CancellationToken cancellationToken)
473	        {
474	            await DoNotify(qs.NotifyTriggerListenersComplete(ctx, instCode, cancellationToken), qs, ctx, cancellationToken).ConfigureAwait(false);
475	            await qs.NotifySchedulerListenersFinalized(ctx.Trigger, cancellationToken).ConfigureAwait(false);
476	
477	            return true;
478	        }
479	
480	        static async ValueTask<bool> DoNotify(ValueTask t,
481	            QuartzScheduler qs,
482	            JobExecutionContextImpl ctx,
483	            CancellationToken cancellationToken)
484	        {
485	            try
486	            {
487	                await t.ConfigureAwait(false);
488	                return true;
489	            }
490	            catch (SchedulerException se)
491	            {
492	                return await NotifyError(se, qs, ctx, cancellationToken).ConfigureAwait(false);
493	            }
494	        }
495	
496	        static async ValueTask<bool> NotifyError(SchedulerException se,
497	            QuartzScheduler qs,
498	            JobExecutionContextImpl ctx,
499	            CancellationToken cancellationToken)
500	        {
501	            string msg = $"Unable to notify TriggerListener(s) of Job that was executed: (error will be ignored). trigger= {ctx.Trigger.Key} job= {ctx.JobDetail.Key}";
502	            await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);
503	            return false;
504	        }
505	    }
506	
507	    [Serializable]
508	    internal sealed class VetoedException : Exception
509	    {
510	        public VetoedException(JobRunShell shell)
511	        {
512	            EnclosingInstance = shell;
513	        }
514	
515	        public JobRunShell EnclosingInstance { get; }
516	    }
517	}

