    }

    /// <summary>
    /// A simple chained job that records when it was executed.
    /// </summary>
    public class SimpleChainedJob : IJob
    {
        public static int ExecutionCount;

        public ValueTask Execute(IJobExecutionContext context)
        {
            ExecutionCount++;
            return default;
        }
    }

    [TearDown]
    public async Task TearDown()
    {
        RefireThenSucceedJob.ExecutionCount = 0;
        RefireThenSucceedJob.RefireBeforeSuccessCount = 0;
        SimpleChainedJob.ExecutionCount = 0;
        if (sched != null)
        {
            await sched.Shutdown();
        }
    }

    [Test]
    public async Task JobChainingListenerShouldNotChainDuringRefireImmediately()
    {
        await sched.Start();

        JobKey firstJobKey = new JobKey("firstJob", "testGroup");
        JobKey secondJobKey = new JobKey("secondJob", "testGroup");

        // Create the first job that will refire 2 times before succeeding
        IJobDetail firstJob = JobBuilder.Create<RefireThenSucceedJob>()
            .WithIdentity(firstJobKey)
            .StoreDurably()
            .Build();

        // Create the second chained job
        IJobDetail secondJob = JobBuilder.Create<SimpleChainedJob>()
            .WithIdentity(secondJobKey)
            .StoreDurably()
            .Build();

        // Setup the chaining listener
        var chainListener = new JobChainingJobListener("testChain");
        chainListener.AddJobChainLink(firstJobKey, secondJobKey);
        sched.ListenerManager.AddJobListener(chainListener);

        // Add both jobs to the scheduler
        await sched.AddJob(firstJob, false);
        await sched.AddJob(secondJob, false);

        // Configure the first job to refire 2 times before succeeding
        RefireThenSucceedJob.RefireBeforeSuccessCount = 2;

        // Trigger the first job
        await sched.TriggerJob(firstJobKey);

        // Wait for the jobs to complete - the first job will refire a couple times,
        // then succeed, then the chained job should fire.
        await Task.Delay(3000);

        await sched.Shutdown(waitForJobsToComplete: true);

        // The first job should have executed 3 times (2 failures + 1 success)
        Assert.That(RefireThenSucceedJob.ExecutionCount, Is.EqualTo(3),
            "First job should have executed 3 times (2 refires + 1 success)");

        // The chained job should have executed exactly once
        Assert.That(SimpleChainedJob.ExecutionCount, Is.EqualTo(1),
            "Chained job should have executed exactly once (only after the first job succeeds)");
    }
